BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?prop ?value ?valueName WHERE {
  BIND(<http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::01%2520Components::Operational::APS::Conceptual%2520Design::Configuration%2520Tables::Wavefront%2520Calibration%2520Lookup%2520Table::Wavefront%2520Calibration%2520Lookup%2520Table> AS ?table)
  ?table ?prop ?value .
  OPTIONAL { ?value vocab:NamedElement_name ?valueName }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?table ?name ?qname WHERE {
  ?table vocab:NamedElement_name ?name .
  FILTER(CONTAINS(LCASE(STR(?name)), LCASE("Wavefront Calibration Lookup Table"))) 
  ?table rdf:type vocab:block .
  OPTIONAL { ?table vocab:NamedElement_qualifiedName ?qname }
}
LIMIT 10

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?prop ?name ?type ?qname WHERE {
  ?prop vocab:NamedElement_name "lookupTableEntry" .
  ?prop rdf:type vocab:part%20property .
  OPTIONAL { ?prop vocab:NamedElement_qualifiedName ?qname }
}
LIMIT 20
